external_knowledge:
- 'gardens' is a metaphor for 'portfolios';
- 'seasoned gardeners' refers to portfolio managers with more than 10 years of experience;
- 'flowers blooming in those gardens' are the companies whose stocks are held in the portfolios.

sql:
SELECT ticker, name
FROM stocks
WHERE sector_id = 0 AND industry_id = 0;

SELECT ticker
FROM portfolio_stocks
WHERE portfolio_id = 1;

SELECT alerts.alert_id, stocks.name 
FROM alerts 
INNER JOIN stocks ON alerts.ticker = stocks.ticker;

SELECT AVG(experience) AS AverageExperience
FROM portfolio_managers
WHERE experience > 5;

SELECT SUM(shares) 
FROM portfolio_stocks 
WHERE portfolio_id = 101;

SELECT SUM(weight * purchase_price) AS total_portfolio_value
FROM portfolio_stocks
WHERE portfolio_id = 1;
